Javascript.validate:
			//Validation: only numeric characters allowed and two decimal places.
			//Error message: Currency amounts must be in the format of 0.00
			//Currency field. Max value. 999999.99	
            var value = Services.getValue(SolicitorCost.dataBinding);      
            var maxVal = 999999.99;         
            var err = null;
                  
            if( '0.00 ' != value )
            {   err = validateCurrencyValue(value, maxVal);
            	if( null == err)
                { 
                	var returnVal = WPU.formatToTwoDP(value);
                    Services.setValue(SolicitorCost.dataBinding, returnVal);
                } 
            }	
            return err;

Javascript.transformToModel:
        
			if( null == value || "" == value )
			{  return "0.00 ";
			}
			else
			{ return value;
			}

Javascript.miscCode:
function DefaultCurrency9111() {}
DefaultCurrency9111.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency9111.tabIndex = -1;
DefaultCurrency9111.maxLength = 1;
DefaultCurrency9111.isReadOnly = function(){return true;}
DefaultCurrency9111.isTemporary = function(){return true;}
DefaultCurrency9111.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency9111.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
